# @cctt_verify {"v":2,"sym":"sympy.matrices.expressions.tests.test_determinant.test_eval_determinant","kind":"function","src_hash":"bee872ffe79812d6","in":{"base":"Any"},"out":{"base":"Any","pred":"det(Identity(n)) == 1 and det(ZeroMatrix(n, n)) == 0 and det(OneMatrix(n, n)) == Determinant(OneMatrix(n, n)) and det(OneMatrix(1, 1)) == 1 and det(OneMatrix(2, 2)) == 0 and det(Transpose(A)) == det(A) and Determinant(MatMul(eye(2), eye(2))).doit(deep=True) == 1"},"spec":{"lhs":"test_eval_determinant()","rhs":"test_eval_determinant produces the expected output","over":{"base":"Any"},"name":"test_eval_determinant_correct"},"guarantee":"test_eval_determinant produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.matrices.expressions.tests.test_determinant.test_eval_determinant_correct","statement":"Path(test_eval_determinant(x), test_eval_determinant produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"ba988a631f521fb9"}
def test_eval_determinant():
    assert det(Identity(n)) == 1
    assert det(ZeroMatrix(n, n)) == 0
    assert det(OneMatrix(n, n)) == Determinant(OneMatrix(n, n))
    assert det(OneMatrix(1, 1)) == 1
    assert det(OneMatrix(2, 2)) == 0
    assert det(Transpose(A)) == det(A)
    assert Determinant(MatMul(eye(2), eye(2))).doit(deep=True) == 1


